        }
        for (int i = 0; i < N; i++) {
            scanf("%lf", &C[i]);
        }
        double time = 0;
        for (int i = 0; i < N; i++) {
            double car_time;
            if (D[i] == 1) {
                car_time = (P[i] + C[i]) / V[i];
            } else {
                car_time = (P[i] - C[i]) / V[i];
            }
