import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int S = sc.nextInt();
            int Y = sc.nextInt();
            double[] V = new double[N];
            double[] D = new double[N];
            double[] P = new double[N];
            double[] C = new double[N];
            for (int i = 0; i < N; i++) {
                V[i] = sc.nextDouble();
            }
            for (int i = 0; i < N; i++) {
                D[i] = sc.nextDouble();
            }
            for (int i = 0; i < N; i++) {
                P[i] = sc.nextDouble();
            }
            for (int i = 0; i < N; i++) {
                C[i] = sc.nextDouble();
            }
            double time = 0;
            for (int i = 0; i < N; i++) {
                double car_time;
                if (D[i] == 1) {
                    car_time = (P[i] + C[i]) / V[i];
                } else {
                    car_time = (P[i] - C[i]) / V[i];
                }
                time = Math.max(time, car_time);
                time += (double) Y / S;
            }
            System.out.printf("%.6f\n", time);
        }
    }
}

