const fs = require('fs');
const lines = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;
const readline = () => lines[idx++];
const T = parseInt(readline());
for (let i = 0; i < T; i++) {
    const [N, S, Y] = readline().split(' ').map(Number);
    const V = readline().split(' ').map(Number);
    const D = readline().split(' ').map(Number);
    const P = readline().split(' ').map(Number);
    const C = readline().split(' ').map(Number);
    let time = 0;
    for (let j = 0; j < N; j++) {
        let car_time;
        if (D[j] === 1) {
            car_time = (P[j] + C[j]) / V[j];
        } else {
            car_time = (P[j] - C[j]) / V[j];
        }
        time = Math.max(time, car_time);
        time += Y / S;
    }
    console.log(time.toFixed(6));
}
